# Use case scoring model: compute portfolio tier placement

from dataclasses import dataclass, field

@dataclass
class ScoringRubric:
    name: str
    weight: float

@dataclass
class UseCase:
    name: str
    value_scores: dict   # sub-dimension: score (1-5)
    feasibility_scores: dict  # sub-dimension: score (1-5)

VALUE_RUBRIC = [
    ScoringRubric("financial_impact", 0.50),
    ScoringRubric("strategic_alignment", 0.30),
    ScoringRubric("risk_reduction", 0.20),
]
FEASIBILITY_RUBRIC = [
    ScoringRubric("data_readiness", 0.40),
    ScoringRubric("model_maturity", 0.35),
    ScoringRubric("integration_complexity", 0.25),  # 5 = simple, 1 = very complex
]

def weighted_score(scores: dict, rubric: list) -> float:
    return sum(scores[r.name] * r.weight for r in rubric if r.name in scores)

def segment(uc: UseCase, threshold: float = 3.0) -> str:
    v = weighted_score(uc.value_scores, VALUE_RUBRIC)
    f = weighted_score(uc.feasibility_scores, FEASIBILITY_RUBRIC)
    if v >= threshold and f >= threshold:
        return "INVEST"
    elif v < threshold and f >= threshold:
        return "INCUBATE"
    elif v >= threshold and f < threshold:
        return "RESEARCH"
    else:
        return "DEPRIORITIZE"

portfolio = [
    UseCase("Contract review agent",
        value_scores={"financial_impact": 4, "strategic_alignment": 5, "risk_reduction": 3},
        feasibility_scores={"data_readiness": 4, "model_maturity": 5, "integration_complexity": 3}
    ),
    UseCase("Predictive maintenance (novel sensor data)",
        value_scores={"financial_impact": 5, "strategic_alignment": 4, "risk_reduction": 4},
        feasibility_scores={"data_readiness": 2, "model_maturity": 2, "integration_complexity": 2}
    ),
    UseCase("Generic chatbot FAQ",
        value_scores={"financial_impact": 2, "strategic_alignment": 2, "risk_reduction": 1},
        feasibility_scores={"data_readiness": 5, "model_maturity": 5, "integration_complexity": 4}
    ),
]

for uc in portfolio:
    v = weighted_score(uc.value_scores, VALUE_RUBRIC)
    f = weighted_score(uc.feasibility_scores, FEASIBILITY_RUBRIC)
    tier = segment(uc)
    print(f"{uc.name[:40]:<40} V={v:.1f} F={f:.1f} -> {tier}")

# Portfolio tier reporting: summarize portfolio by tier

def portfolio_summary(use_cases: list, rubric_fn) -> dict:
    summary = {"INVEST": [], "INCUBATE": [], "RESEARCH": [], "DEPRIORITIZE": []}
    for uc in use_cases:
        tier = rubric_fn(uc)
        summary[tier].append(uc.name)
    return summary

# Governance action map per tier
TIER_ACTIONS = {
    "INVEST":       {"governance": "Full MRM review", "resourcing": "Senior team", "timeline": "Standard delivery"},
    "INCUBATE":     {"governance": "Lightweight review", "resourcing": "20% capacity", "timeline": "Time-boxed 3 months"},
    "RESEARCH":     {"governance": "Innovation gate", "resourcing": "Innovation pod", "timeline": "Time-boxed 90 days"},
    "DEPRIORITIZE": {"governance": "None", "resourcing": "None", "timeline": "Archive"},
}
for tier, action in TIER_ACTIONS.items():
    print(f"\n{tier}:")
    for k, v in action.items():
        print(f"  {k}: {v}")
